form:Form.form:Scripts:
		function val_f_ini_estudio(Me)
{
	if (Me.TypedValue() != null)
	{
		if (Me.TypedValue() > NowDate())
		{
			Me.SetError('La fecha de Inicio de Estudio debe ser anterior o igual a la fecha Actual');
			return false;								
		}	
		else return true;
	}				
	else return true;
}

function val_f_fin_estudio(Me)
{
	if (Me.TypedValue() != null)
	{
		if (Me.TypedValue() > NowDate())
		{
			Me.SetError('La fecha de Fin de Estudio debe ser anterior o igual a la Fecha Actual');
			return false;
		}						
		else 
		if (Ctrl('f_ini_estudio').TypedValue() != null)
		{
			if (Ctrl('f_ini_estudio').TypedValue() >= Me.TypedValue())
			{
				Me.SetError('La fecha de Fin de Estudio debe ser posterior a la fecha de Inicio de Estudio');
				return false
			}
			else return true
		}
		else return true
	}
	else return true;
}

function val_f_act_estudio(Me)
{
	if (Me.TypedValue() != null)
	{
		if (Me.TypedValue() < Ctrl('f_ini_estudio').TypedValue())
		{
			Me.SetError('La fecha de Actualización debe ser anterior o igual a la fecha de Inicio de Estudio');
			return false;								
		}	
		else return true;
	}				
	else return true;
}

function val_est_educ(Me)
{
	if (Me.GetXValue() == "")
	{
		Me.SetError("Debe especificar el establecimiento educativo en el campo 'Otros'");
		return false;
	}
	else return true;
}
